        tup_arr = tuple(arr)
        if tup_arr in dp:
            return dp[tup_arr]

        if not arr:
            return 0

        if len(arr) <= 2:
            return max(arr)

        if len(arr) == 3:
            return max(arr)

        min_cost = float('inf')

        for i in range(min(3, len(arr))):
            for j in range(i + 1, min(3, len(arr))):
                cost = max(arr[i], arr[j])
                remaining_arr = []
                for k in range(len(arr)):
                    if k != i and k != j:
                        remaining_arr.append(arr[k])

                min_cost = min(min_cost, cost + solve(remaining_arr))

        dp[tup_arr] = min_cost
        return min_cost

    return solve(nums)
